SET academy_metadata = '{"displayName":"Canada – Spouse / Dependent Status Extension","shortDescription":"IRCC · Extend spouse/dependant temporary status in Canada","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 10 Jun 2026","learningLevel":"Intermediate","learningMinutes":18,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Spouse/dependent OWP rules change frequently. Verify principal applicant category, occupation/program eligibility, and dependant criteria on canada.ca before quoting."},"alert":{"title":"Principal status alignment","body":"Extension must align with principal applicant''s valid status and expiry timeline."},"tags":[{"label":"Active service","variant":"success"},{"label":"Family eligibility","variant":"warning"},{"label":"3–5 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"3–5 months processing","variant":"neutral"},{"label":"CAD $255 approx","variant":"neutral"},{"label":"Open work permit","variant":"success"},{"label":"Principal status required","variant":"warning"}],"kpis":[{"label":"Processing time","value":"3–5m","sub":"Varies by applicant location","tone":"primary"},{"label":"Government fee","value":"CAD $255","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"88%","sub":"~76% benchmark","tone":"success"},{"label":"Required docs","value":"13","sub":"+ relationship proof","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Open work permit pathway for eligible spouses, common-law partners, or qualifying dependants linked to a principal applicant''s Canadian work, study, or immigration status."},{"label":"Eligible applicants","value":"Genuine spouse/common-law partner or eligible dependant · Principal applicant has qualifying status · Relationship documents · Funds and admissibility evidence"},{"label":"Rule sensitivity","value":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Applicant may work for most employers in Canada subject to printed conditions. Review expiry alignment with principal applicant status."}],"eligibility":[{"criterion":"Principal applicant holds valid status or approved extension","met":true},{"criterion":"Relationship still genuine and documented","met":true},{"criterion":"Application filed before current status expires","met":true},{"criterion":"Funds and admissibility evidence current","met":false},{"criterion":"Correct extension form and fees selected","met":true}],"redFlagsBanner":"Most weak spouse/dependent OWP files fail because the principal applicant does not qualify, the relationship proof is thin, or prior refusals are not addressed.","redFlags":[{"title":"Principal applicant not eligible","description":"Principal worker, student, or PR applicant category does not support dependant OWP.","fix":"Verify current IRCC category before taking full file; assess visitor or other status options","severity":"High"},{"title":"Weak relationship proof","description":"Marriage certificate only, limited photos, no communication, or no shared life evidence.","fix":"Add relationship timeline, photos, chats, travel, financial, and family evidence","severity":"Very common"},{"title":"Recent marriage before filing","description":"Marriage occurred shortly before application with limited relationship history.","fix":"Prepare detailed relationship narrative and third-party corroboration","severity":"Common"},{"title":"Prior refusals not disclosed","description":"Applicant or principal has previous Canada or other country refusals omitted from forms.","fix":"Disclose all refusals and address changed circumstances","severity":"High"},{"title":"Principal status expiring soon","description":"Principal permit expires shortly, limiting dependant permit duration or eligibility.","fix":"Coordinate principal extension or wait for renewed status where strategic","severity":"Common"},{"title":"Insufficient funds","description":"Family cannot show credible support for living costs in Canada.","fix":"Add bank history, employment income, pay stubs, and sponsor explanation","severity":"Medium"},{"title":"Inconsistent forms","description":"Dates, addresses, marital status, or family details conflict across forms.","fix":"Run consistency review against passport, marriage, and prior applications","severity":"Common"}],"faqs":[{"q":"Can every spouse of a student get an open work permit?","a":"No. Eligibility depends on current IRCC rules, the student''s program and institution, and other conditions."},{"q":"Can every spouse of a worker get an open work permit?","a":"No. The principal worker''s occupation, permit type, and status must qualify under current policy."},{"q":"Is a marriage certificate enough?","a":"Usually not by itself. Provide relationship history, photos, communication, travel, financial ties, and family evidence where available."},{"q":"Can common-law partners apply?","a":"Yes, if they meet IRCC''s common-law definition and can prove cohabitation and genuine relationship."},{"q":"Can dependent children get open work permits?","a":"Only in limited circumstances. Many children need visitor or study status instead. Screen age and dependency rules carefully."},{"q":"Should the application be filed together with the principal applicant?","a":"Sometimes. It depends on timing, principal eligibility, documents, and risk. Joint filing can help context but is not always best."},{"q":"How long will the OWP be valid?","a":"Often tied to the principal applicant''s status and passport validity. IRCC decides the final duration."},{"q":"Can the applicant work while waiting?","a":"Only if they already have authorization and meet maintained status rules. Outside-Canada applicants cannot work until approved and admitted with proper status."},{"q":"What if there was a previous spouse OWP refusal?","a":"Order notes if useful, address refusal reasons directly, and strengthen principal eligibility and relationship evidence."},{"q":"Does approval lead to PR?","a":"No. OWP is temporary status. It may support Canadian work experience, but PR requires a separate pathway."},{"q":"What is Description for this service?","a":"Open work permit pathway for eligible spouses, common-law partners, or qualifying dependants linked to a principal applicant''s Canadian work, study, or immigration status."},{"q":"What is Eligible applicants for this service?","a":"Genuine spouse/common-law partner or eligible dependant · Principal applicant has qualifying status · Relationship documents · Funds and admissibility evidence"},{"q":"What is Rule sensitivity for this service?","a":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules."},{"q":"Important note on Rule sensitivity?","a":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Applicant may work for most employers in Canada subject to printed conditions. Review expiry alignment with principal applicant status."},{"q":"Is Principal applicant has valid qualifying status in Canada or approved pathway required?","a":"Principal applicant has valid qualifying status in Canada or approved pathway is typically required."},{"q":"Is Applicant is spouse, common-law partner, or qualifying dependant under IRCC rules required?","a":"Applicant is spouse, common-law partner, or qualifying dependant under IRCC rules is typically required."},{"q":"Is Relationship is genuine and well documented required?","a":"Marriage certificate alone may not be enough"},{"q":"Is Principal worker occupation, employer, or permit category qualifies where required required?","a":"Principal worker occupation, employer, or permit category qualifies where required is typically required."},{"q":"Is Principal student program and institution qualify where required required?","a":"Principal student program and institution qualify where required is typically required."},{"q":"Is Applicant passport valid for requested permit period required?","a":"Applicant passport valid for requested permit period is typically required."},{"q":"Is Applicant has no inadmissibility, misrepresentation, or undisclosed refusal issue required?","a":"Applicant has no inadmissibility, misrepresentation, or undisclosed refusal issue is typically required."},{"q":"Is Funds or family support evidence available for settlement and stay required?","a":"Funds or family support evidence available for settlement and stay is typically required."},{"q":"Is Medical exam or biometrics completed if required required?","a":"Assess whether Medical exam or biometrics completed if required is satisfied for this case."},{"q":"What is the Processing time?","a":"3–5m — Varies by applicant location"},{"q":"What is the Government fee?","a":"CAD $255 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"88% — ~76% benchmark"},{"q":"What is the Required docs?","a":"13 — + relationship proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee open work permit approval or work rights before authorization","Confirm paid representation authority for Canadian immigration filings","Fee quotes must separate consultancy, government, biometrics, medical, and third-party costs"],"proTips":["Screen the principal applicant first before building the dependant file","Create a relationship timeline with dates matching forms and documents","Use current IRCC rules for spouses of students and workers before quoting eligibility","Coordinate expiry dates between principal and dependant passports","Address prior refusals in the cover letter instead of hoping they are ignored","Run a final consistency check across all family forms"],"postApproval":["Send approval and permit condition summary to applicant","Explain work restrictions printed on the permit, if any","Coordinate travel, TRV/eTA, and port of entry steps where applicable","Review SIN application or update process after arrival/approval","Calendar expiry alongside principal applicant status"],"performance":{"ourRate":88,"industryRate":76,"stats":[{"label":"Files this year","value":"86"},{"label":"Approved","value":"76"},{"label":"Refused","value":"8"},{"label":"Withdrawn","value":"2"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":88,"benchmark":76},{"label":"Principal eligibility","ours":90,"benchmark":72},{"label":"Relationship evidence","ours":86,"benchmark":70},{"label":"Form consistency","ours":92,"benchmark":78}],"timeline":[{"weeks":"1","title":"Principal eligibility and relationship screening"},{"weeks":"1–3","title":"Relationship, status, funds, and form preparation"},{"weeks":"3","title":"Quality review and IRCC submission"},{"weeks":"3–5m","title":"IRCC processing, biometrics, and decision"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – BOWP","libraryId":""},{"label":"Canada – Visitor Record","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary