ure Link consultancy fee","range":"See Fees tab","notes":"Service package dependent"},{"label":"Flight / travel","range":"₹40,000–1,20,000","notes":"Season and route"},{"label":"Document translation / notary","range":"₹2,000–15,000"},{"label":"Courier & VFS premium services","range":"Optional"},{"label":"Forex / transfer charges","range":"Bank dependent","notes":"GIC, blocked account, tuition transfers"}]}],"totals":[{"label":"Indicative first-year budget (excl. tuition band)","value":"Counselor to calculate from sections above","notes":"Always cross-check LOA/CAS/Offer of Place and official fee pages before client commitment."}]}}'::jsonb, updated_at = now()
