SET academy_metadata = '{"displayName":"Canada – Spouse / Partner Sponsorship","shortDescription":"IRCC family sponsorship · Inland & outland · PR pathway for spouses","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":25,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current IRCC spousal sponsorship fees (principal + right of permanent residence fee) on canada.ca before quoting."},"alert":{"title":"Genuine relationship evidence","body":"Officers scrutinise relationship genuineness. Weak or inconsistent evidence is a leading refusal factor—build a chronological, document-backed story."},"tags":[{"label":"Active service","variant":"success"},{"label":"Relationship proof critical","variant":"warning"},{"label":"12–18 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"12–18 months processing","variant":"neutral"},{"label":"CAD $1,150+ fees","variant":"neutral"},{"label":"Genuine relationship","variant":"warning"},{"label":"Inland or outland","variant":"success"}],"kpis":[{"label":"Processing time","value":"12–18m","sub":"Varies by stream and office","tone":"primary"},{"label":"Government fee","value":"CAD $1,150+","sub":"+ biometrics, medical","tone":"warning"},{"label":"Our approval rate","value":"91%","sub":"~82% industry benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ relationship evidence","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is in Canada."},{"label":"Eligible applicants","value":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"label":"Inland vs outland","value":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Partner receives COPR and completes landing. Maintain relationship genuineness obligations; misrepresentation has serious consequences."}],"eligibility":[{"criterion":"Sponsor is Canadian citizen or PR aged 18+","met":true,"note":"Verify sponsor status and residency obligations"},{"criterion":"Legally valid marriage or qualifying relationship","met":true,"note":"Marriage certificate; common-law needs 12+ months cohabitation proof"},{"criterion":"Genuine relationship evidence","met":true,"note":"Photos, communication, financial mingling, visits"},{"criterion":"Sponsor not in default of prior sponsorship undertakings","met":true},{"criterion":"Medical exam completed","met":false,"note":"Panel physician after instructions"},{"criterion":"Police certificates as required","met":false,"note":"Based on residence history"},{"criterion":"Biometrics completed","met":false,"note":"Both sponsor and applicant if required"}],"redFlagsBanner":"If refused for relationship genuineness, do not reapply with the same weak evidence. Rebuild a chronological, verifiable relationship narrative first.","redFlags":[{"title":"Weak relationship evidence","description":"Few photos, no communication logs, short relationship timeline, or inconsistent stories.","fix":"Chronological timeline; chat/call logs; joint finances; visit stamps; affidavits from family","severity":"Very common"},{"title":"Marriage of convenience suspicion","description":"Large age gap without explanation, met only days before marriage, or prior failed sponsorships.","fix":"Honest narrative; explain how relationship developed; strong third-party support","severity":"High"},{"title":"Incomplete sponsor eligibility","description":"Sponsor on social assistance, prior undertaking default, or not meeting residency for PR sponsors.","fix":"Verify sponsor eligibility checklist on canada.ca before fee collection","severity":"High"},{"title":"Wrong stream (inland vs outland)","description":"Applied inland when partner cannot remain legally in Canada, or outland without travel plan clarity.","fix":"Assess partner''s current status; choose stream with legal counsel if complex","severity":"Common"},{"title":"Missing or inconsistent forms","description":"IMM forms incomplete, dates mismatch across documents, or unsigned declarations.","fix":"Cross-check all dates; dual review before upload","severity":"Common"},{"title":"Undisclosed prior relationships or refusals","description":"Hidden prior marriages, refusals, or misrepresentation history.","fix":"Full disclosure; address changed circumstances in cover letter","severity":"High"}],"faqs":[{"q":"Can we guarantee PR approval for a genuine marriage?","a":"No. Even genuine couples can face requests for additional evidence or refusal if documentation is weak. We improve file quality but never promise approval."},{"q":"Inland or outland—which is faster?","a":"Timelines vary and change. Outland may allow partner to visit during processing; inland may offer open work permit eligibility. Assess case-by-case."},{"q":"How much relationship evidence is enough?","a":"No fixed amount—officers want a credible chronological story: how you met, communication, visits, marriage, shared life plans. Quality over quantity."},{"q":"Can a sponsored spouse work while waiting?","a":"Inland applicants may apply for open work permit after AIP stage in many cases. Verify current IRCC rules at time of counseling."},{"q":"What if marriage is recent?","a":"Recent marriages need stronger evidence—communication history before marriage, visit records, photos, and explanation of relationship development."},{"q":"Does sponsor need minimum income?","a":"Spousal sponsorship generally has no LICO requirement for spouse/partner/child, but sponsor must not be on social assistance (except disability) and must meet undertaking obligations."},{"q":"What happens after refusal?","a":"Review refusal letter carefully. Options may include appeal (IAD) for in-Canada refusals in some cases, or reapplication with stronger evidence."},{"q":"Are common-law partners eligible?","a":"Yes, if they have cohabited continuously for at least 12 months. Evidence of shared residence is essential."},{"q":"What is Description for this service?","a":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is in Canada."},{"q":"What is Eligible applicants for this service?","a":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"q":"What is Inland vs outland for this service?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"Important note on Inland vs outland?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Partner receives COPR and completes landing. Maintain relationship genuineness obligations; misrepresentation has serious consequences."},{"q":"Is Sponsor is Canadian citizen or PR aged 18+ required?","a":"Verify sponsor status and residency obligations"},{"q":"Is Legally valid marriage or qualifying relationship required?","a":"Marriage certificate; common-law needs 12+ months cohabitation proof"},{"q":"Is Genuine relationship evidence required?","a":"Photos, communication, financial mingling, visits"},{"q":"Is Sponsor not in default of prior sponsorship undertakings required?","a":"Sponsor not in default of prior sponsorship undertakings is typically required."},{"q":"Is Medical exam completed required?","a":"Panel physician after instructions"},{"q":"Is Police certificates as required required?","a":"Based on residence history"},{"q":"Is Biometrics completed required?","a":"Both sponsor and applicant if required"},{"q":"What is the Processing time?","a":"12–18m — Varies by stream and office"},{"q":"What is the Government fee?","a":"CAD $1,150+ — + biometrics, medical"},{"q":"What is the Our approval rate?","a":"91% — ~82% industry benchmark"},{"q":"What is the Required docs?","a":"18 — + relationship evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak relationship evidence?","a":"Chronological timeline; chat/call logs; joint finances; visit stamps; affidavits from family"},{"q":"Why is Weak relationship evidence a problem?","a":"Few photos, no communication logs, short relationship timeline, or inconsistent stories."},{"q":"What if the client has Marriage of convenience suspicion?","a":"Honest narrative; explain how relationship developed; strong third-party support"},{"q":"Why is Marriage of convenience suspicion a problem?","a":"Large age gap without explanation, met only days before marriage, or prior failed sponsorships."}],"compliance":["Spousal sponsorship requires licensed RCIC or lawyer for paid representation in Canada—confirm credentials","Client service agreement and consent must be on file before submission","Never guarantee PR approval; marriage alone does not ensure success","Fee quotes must separate consultancy, government, medical, and biometrics"],"proTips":["Build a relationship timeline document before collecting forms","Cross-check every date across marriage cert, photos, and travel history","For recent marriages, include pre-marriage communication evidence","Verify sponsor eligibility before taking full fees","Save relationship evidence binder separately for RFI responses"],"postApproval":["Send COPR and landing instructions to client in writing","Remind client of PR card application after landing","Explain sponsor undertaking period (typically 3 years for spouse)","Register for post-landing settlement briefing if offered"],"performance":{"ourRate":91,"industryRate":82,"stats":[{"label":"Files this year","value":"47"},{"label":"Approved","value":"43"},{"label":"Refused","value":"3"},{"label":"Withdrawn","value":"1"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":91,"benchmark":82},{"label":"Relationship evidence quality","ours":88,"benchmark":72},{"label":"Form accuracy","ours":94,"benchmark":78},{"label":"Complete checklist first submit","ours":90,"benchmark":75}],"timeline":[{"weeks":"1–2","title":"Counseling, sponsor eligibility check, fee agreement"},{"weeks":"2–6","title":"Relationship evidence collection, forms, medical/police"},{"weeks":"6–8","title":"Quality review & IRCC submission"},{"weeks":"8–12","title":"Acknowledgement of receipt (AOR)"},{"weeks":"12–18m","title":"Processing to decision (varies)"}],"relatedServices":[{"label":"Canada – Visitor Visa (TRV)","libraryId":""},{"label":"Canada – Express Entry PR","libraryId":""},{"label":"Canada – Work Permit","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial counselor content for Canada spousal sponsorship with 2026 fee notes."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Arranged marriages need extra care—build pre-marriage communication evidence and family affidavits without appearing fabricated."},{"author":"Quality","date":"6 Jun 2026","text":"Mandatory dual review for all spousal files—date mismatches are the top internal QA finding."}],"resources":[{"title":"IRCC — Sponsor your spouse, partner or child","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/family-sponsorship/spouse-partner-children.html","description":"Official sponsorship requirements and application guide"},{"title":"IRCC — Check processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current spousal sponsorship processing estimates"},{"title":"IRCC — Application fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-application-fees.html","description":"Current sponsorship and right of PR fees"},{"title":"IRCC — Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"Biometrics requirements for family class"},{"title":"IRCC — Medical exams","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/medical-police/medical-exams.html","description":"When and how to complete immigration medical exam"}],"quiz":[{"question":"What is a leading refusal reason in spousal sponsorship?","options":["Passport colour","Weak or inconsistent relationship evidence","Hotel bookings","Language test scores"],"correctIndex":1,"explanation":"Officers must be satisfied the relationship is genuine.","level":1},{"question":"Common-law partners must generally show:","options":["1 month cohabitation","12+ months continuous cohabitation","No evidence needed","Only wedding photos"],"correctIndex":1,"explanation":"IRCC requires at least 12 months of continuous cohabitation for common-law.","level":1},{"question":"Can counselors guarantee PR for genuine marriages?","options":["Yes, always","No, never guarantee approval","Yes, if married 5+ years","Yes, if sponsor is citizen"],"correctIndex":1,"explanation":"Firm policy: never guarantee immigration outcomes.","level":1},{"question":"Inland sponsorship may allow the partner to:","options":["Skip medical exam","Apply for open work permit in many cases while awaiting decision","Work without any permit immediately","Leave Canada permanently without impact"],"correctIndex":1,"explanation":"Inland stream has specific work permit options—verify current rules.","level":1},{"question":"Before submission, counselors must verify:","options":["Sponsor eligibility and complete relationship timeline","Only marriage certificate","Client''s school marks","Hotel reservations in Canada"],"correctIndex":0,"explanation":"Sponsor eligibility and relationship narrative are foundational.","level":1},{"level":1,"question":"For Canada – Spouse / Partner Sponsorship, which statement about Description is correct?","options":["Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outlan…","Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clea…","Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","Immigration, Refugees and Citizenship Canada (IRCC)"],"correctIndex":0,"explanation":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is i…"},{"level":1,"question":"Canada – Spouse / Partner Sponsorship: what is true regarding Eligible applicants?","options":["Legally m